### Sync RxDB with Custom Endpoint using JavaScript

Source: https://github.com/pubkey/rxdb/blob/master/docs/articles/firebase-realtime-database-alternative.html

Demonstrates how to set up RxDB with a local storage plugin and then initiate a custom replication process. This involves defining push and pull handlers to sync data with a specified backend API. It assumes the existence of a 'tasks' collection with a defined schema. The replication can run live, continuously syncing changes.

```javascript
import { createRxDatabase } from 'rxdb/plugins/core';
import { getRxStorageLocalstorage } from 'rxdb/plugins/storage-localstorage';
import { replicateRxCollection } from 'rxdb/plugins/replication';

async function initDB() {
  const db = await createRxDatabase({
    name: 'localdb',
    storage: getRxStorageLocalstorage(),
    multiInstance: true,
    eventReduce: true
  });

  await db.addCollections({
    tasks: {
      schema: {
        title: 'task schema',
        version: 0,
        type: 'object',
        primaryKey: 'id',
        properties: {
          id: { type: 'string', maxLength: 100 },
          title: { type: 'string' },
          complete: { type: 'boolean' }
        }
      }
    }
  });

  // Start a custom replication
  replicateRxCollection({
    collection: db.tasks,
    replicationIdentifier: 'custom-tasks-api',
    push: {
      handler: async (docs) => {
        // post local changes to your server
        const resp = await fetch('https://yourapi.com/tasks/push', {
          method: 'POST',
          body: JSON.stringify({ changes: docs })
        });
        return await resp.json(); // return conflicting documents if any
      }
    },
    pull: {
      handler: async (lastCheckpoint, batchSize) => {
        // fetch new/updated items from your server
        const response = await fetch(
          `https://yourapi.com/tasks/pull?checkpoint=${JSON.stringify(
            lastCheckpoint
          )}&limit=${batchSize}`
        );
        return await response.json();
      }
    },
    live: true
  });

  return db;
}
```

